$(document).ready(function(){$(".form").each(function(){$(this).find("input, textarea").each(function(){$(this).keyup(function(){checkField($(this))})})});$(".form").each(function(){$(this).find("select").each(function(){$(this).on("change",function(){checkField($(this))})})});function checkField(field){console.log(field.val());if(field.val()==""||field.val()==null||field.val()==undefined){field.addClass("empty_field").removeClass("not_empty_field")}else{field.removeClass("empty_field").addClass("not_empty_field")}}$(".login-block-toggle").click(function(event){$(this).toggleClass("active");$(".login-block").toggleClass("active");$(".login-block-overlay").toggle()});$(".login-block-overlay").click(function(event){$(".login-block-toggle").removeClass("active");$(".login-block").removeClass("active");$(this).hide()});var nav=$(".nav");var checkScroll=function(){var scrTop=$(this).scrollTop();if(scrTop<=0&&nav.hasClass("fixed")){nav.removeClass("fixed")}if(scrTop>0&&!nav.hasClass("fixed")){nav.addClass("fixed")}};checkScroll();$(window).scroll(function(){checkScroll()});var offset=$(window).width()>=980?90:50;$(".one-page").onePageNav({scrollThreshold:.4,scrollOffset:offset});$(".scrTo").click(function(e){e.preventDefault();ScrollToAnchor($(this).attr("href"));$("body").removeClass("open")});function ScrollToAnchor(id){var offset=$(id).offset().top;$("html, body").animate({scrollTop:offset-79},250);return false}var toggleMenuProcc=false;$(".toggle-nav").click(function(e){if(!toggleMenuProcc){toggleMenuProcc=true;$(".nav-wrapper").fadeToggle(function(){toggleMenuProcc=false});$(this).toggleClass("open")}});$(".nav a").click(function(e){$(".nav-wrapper").fadeOut();$(".toggle-nav").removeClass("open")});$("form").on("submit",function(){switch($(this).attr("id")){case"signup-form":gtag("event","signup",{event_category:"engagement"});break;case"login-form":gtag("event","login",{event_category:"engagement"});break;case"contacts_cooins":gtag("event","contact",{event_category:"engagement"});break;default:break}})});